import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import axios from 'axios';
import ArtisanCard from '../components/ArtisanCard';

const SearchResults = () => {
    const [artisans, setArtisans] = useState([]);
    const [loading, setLoading] = useState(true);
    const { search } = useLocation();
    const params = new URLSearchParams(search);
    const query = params.get('q');
    const category = params.get('category');

    useEffect(() => {
        setLoading(true);
        axios.get(`http://localhost:5000/api/artisans/search${search}`)
            .then(res => {
                setArtisans(res.data);
                setLoading(false);
            })
            .catch(err => {
                console.error("Erreur lors de la recherche:", err);
                setLoading(false);
            });
            
    }, [search]); 

    if (loading) {
        return (
            <div className="container py-5 text-center">
                <div className="spinner-border text-primary" role="status"></div>
                <p className="mt-2">Recherche des artisans en cours...</p>
            </div>
        );
    }

    return (
        <div className="search-results-container">
            <div className="container py-4">
                <h2 className="mb-5 text-center fw-bold" style={{ color: '#00497c' }}>
                    {category ? `Artisans : ${category}` : `Résultats pour : "${query || ''}"`}
                </h2>
                <div className="artisan-grid">
                    {artisans.length > 0 ? (
                        artisans.map(artisan => (
                            <ArtisanCard key={artisan.id} artisan={artisan} />
                        ))
                    ) : (
                        <div className="col-12 text-center py-5">
                            <div className="alert alert-info">
                                Aucun artisan ne correspond à votre sélection pour le moment.
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default SearchResults;
